{
    "level": "A2–B1",
    "intro": "W tym temacie nauczysz się <strong>porównywać elementy pod względem równości</strong> za pomocą konstrukcji <em>as...as</em> i <em>not as...as</em>, które są ważną alternatywą dla zwykłych stopni porównania.",
    "rules": [
        {
            "label": "AS...AS",
            "color": "emerald",
            "text": "<strong>Równość</strong> — coś jest takie samo jak coś innego:",
            "example": "He is as tall as his brother."
        },
        {
            "label": "NOT AS...AS",
            "color": "rose",
            "text": "<strong>Nierówność</strong> — coś nie jest takie samo jak coś innego:",
            "example": "She is not as tall as her brother."
        },
        {
            "label": "STRUCTURE",
            "color": "blue",
            "text": "Wzór: <strong>as + adjective/adverb + as</strong>",
            "example": "as fast as, as beautiful as, as quickly as"
        }
    ]
}

{
    "title": "1. Podstawowa struktura as...as",
    "intro": "Konstrukcja <strong>as...as</strong> służy do wyrażania równości między dwoma elementami:",
    "rows": [
        {
            "en": "Subject + be + as + adjective + as + object",
            "ua": "Podmiot + be + as + adjective + as + object",
            "note": "Podstawowy wzór dla przymiotników"
        },
        {
            "en": "He is as tall as me.",
            "ua": "On jest tak wysoki jak ja.",
            "note": "✓ równość wzrostu"
        },
        {
            "en": "This book is as interesting as that one.",
            "ua": "Ta książka jest tak samo interesująca jak tamta."
            ,"note": "✓ równość pod względem zainteresowania"
        },
        {
            "en": "Subject + verb + as + adverb + as + object",
            "ua": "Podmiot + czasownik + as + adverb + as + object",
            "note": "Podstawowy wzór dla przysłówków"
        },
        {
            "en": "She runs as fast as her sister.",
            "ua": "Ona biega tak szybko jak jej siostra.",
            "note": "✓ równość szybkości"
        },
        {
            "en": "He works as hard as anyone.",
            "ua": "On pracuje tak ciężko jak każdy inny.",
            "note": "✓ równość pod względem wysiłku"
        }
    ],
    "warning": "💡 Pamiętaj: między dwoma <strong>as</strong> zawsze stoi <strong>forma podstawowa</strong> przymiotnika albo przysłówka, a nie comparative."
}

{
    "title": "2. Użycie as...as dla równości",
    "sections": [
        {
            "label": "Równość z przymiotnikami",
            "color": "emerald",
            "description": "Użyj <strong>as...as</strong>, gdy chcesz powiedzieć, że dwie rzeczy są <strong>takie same</strong> pod jakimś względem:",
            "examples": [
                {
                    "en": "My car is as expensive as yours.",
                    "ua": "Mój samochód jest tak samo drogi jak twój."
                },
                {
                    "en": "This task is as difficult as the previous one.",
                    "ua": "To zadanie jest tak samo trudne jak poprzednie."
                },
                {
                    "en": "He is as smart as his father.",
                    "ua": "On jest tak samo inteligentny jak jego ojciec."
                }
            ]
        },
        {
            "label": "Równość z przysłówkami",
            "color": "blue",
            "description": "Użyj <strong>as...as</strong> z przysłówkami, aby porównać <strong>czynności</strong>:",
            "examples": [
                {
                    "en": "She sings as beautifully as a professional.",
                    "ua": "Ona śpiewa tak pięknie jak profesjonalistka."
                },
                {
                    "en": "He speaks English as fluently as a native.",
                    "ua": "On mówi po angielsku tak płynnie jak native speaker."
                },
                {
                    "en": "They work as efficiently as we do.",
                    "ua": "Oni pracują tak samo skutecznie jak my."
                }
            ]
        },
        {
            "label": "Z wyrażeniami ilościowymi",
            "color": "amber",
            "description": "Konstrukcja <strong>as...as</strong> może łączyć się z <strong>much/many</strong>, gdy porównujemy ilość:",
            "examples": [
                {
                    "en": "I have as much money as you.",
                    "ua": "Mam tyle samo pieniędzy co ty."
                },
                {
                    "en": "She has as many friends as her sister.",
                    "ua": "Ona ma tylu samych przyjaciół co jej siostra."
                },
                {
                    "en": "We need as much time as possible.",
                    "ua": "Potrzebujemy tyle czasu, ile tylko się da."
                }
            ]
        }
    ]
}

{
    "title": "3. Struktura not as...as",
    "intro": "Konstrukcja <strong>not as...as</strong> służy do wyrażania <strong>nierówności</strong> — gdy coś jest mniejsze, słabsze albo gorsze od czegoś innego:",
    "rows": [
        {
            "en": "Subject + be + not as + adjective + as + object",
            "ua": "Podmiot + be + not as + adjective + as + object",
            "note": "Podstawowy wzór dla porównania negatywnego"
        },
        {
            "en": "He is not as tall as me.",
            "ua": "On nie jest tak wysoki jak ja.",
            "note": "✓ jest niższy"
        },
        {
            "en": "This book is not as interesting as that one.",
            "ua": "Ta książka nie jest tak interesująca jak tamta."
            ,"note": "✓ jest mniej interesująca"
        },
        {
            "en": "The weather is not as cold as yesterday.",
            "ua": "Pogoda nie jest tak zimna jak wczoraj.",
            "note": "✓ dziś jest cieplej"
        },
        {
            "en": "She doesn't run as fast as her sister.",
            "ua": "Ona nie biega tak szybko jak jej siostra.",
            "note": "✓ biega wolniej"
        }
    ],
    "warning": "💡 <strong>Not as...as</strong> = mniej ... niż. To łagodniejszy sposób powiedzenia, że coś jest gorsze, słabsze albo mniejsze."
}

{
    "title": "4. Not as...as a bardziej bezpośrednie formy",
    "sections": [
        {
            "label": "Łagodniejszy sposób krytyki",
            "color": "rose",
            "description": "<strong>Not as...as</strong> to <strong>grzeczniejszy sposób</strong> powiedzenia, że coś jest gorsze:",
            "examples": [
                {
                    "en": "It's not as good as I expected.",
                    "ua": "To nie jest tak dobre, jak się spodziewałem."
                },
                {
                    "en": "It's worse than I expected.",
                    "ua": "To jest gorsze, niż się spodziewałem."
                },
                {
                    "en": "She is not as experienced as him.",
                    "ua": "Ona nie jest tak doświadczona jak on."
                }
            ]
        },
        {
            "label": "Różnica znaczeniowa",
            "color": "blue",
            "description": "<strong>Not as...as</strong> skupia się na <strong>braku równości</strong>, a nie na ostrym, bezpośrednim porównaniu:",
            "examples": [
                {
                    "en": "This car is not as fast as mine.",
                    "ua": "Ten samochód nie jest tak szybki jak mój."
                },
                {
                    "en": "This car is slower than mine.",
                    "ua": "Ten samochód jest wolniejszy niż mój."
                },
                {
                    "en": "The test wasn't as hard as I thought.",
                    "ua": "Test nie był tak trudny, jak myślałem."
                }
            ]
        },
        {
            "label": "W pozytywnym kontekście",
            "color": "emerald",
            "description": "<strong>Not as...as</strong> może też wyrażać <strong>miłe zaskoczenie</strong>:",
            "examples": [
                {
                    "en": "The exam wasn't as difficult as I feared.",
                    "ua": "Egzamin nie był tak trudny, jak się obawiałem."
                },
                {
                    "en": "The price is not as high as expected.",
                    "ua": "Cena nie jest tak wysoka, jak oczekiwano."
                },
                {
                    "en": "Learning English isn't as hard as people say.",
                    "ua": "Nauka angielskiego nie jest tak trudna, jak mówią ludzie."
                }
            ]
        }
    ]
}

{
    "title": "5. Częste wyrażenia z as...as",
    "intro": "Istnieją <strong>utarte wyrażenia</strong> z konstrukcją as...as, które warto zapamiętać:",
    "items": [
        {
            "label": "as soon as possible",
            "title": "jak najszybciej",
            "subtitle": "Please reply as soon as possible."
        },
        {
            "label": "as far as I know",
            "title": "o ile wiem",
            "subtitle": "As far as I know, he's not coming."
        },
        {
            "label": "as long as",
            "title": "tak długo jak / pod warunkiem że",
            "subtitle": "You can stay as long as you want."
        },
        {
            "label": "as well as",
            "title": "tak samo jak / a także",
            "subtitle": "She speaks French as well as English."
        },
        {
            "label": "as much as",
            "title": "tyle samo / równie bardzo",
            "subtitle": "I like it as much as you do."
        },
        {
            "label": "as many as",
            "title": "aż tyle / tyle samo (dla policzalnych)",
            "subtitle": "There were as many as 500 people."
        }
    ]
}

{
    "title": "6. Różnica: as...as vs comparative",
    "intro": "Czasami można użyć obu form, ale z <strong>innym odcieniem znaczeniowym</strong>:",
    "rows": [
        {
            "en": "He is as tall as me.",
            "ua": "On jest tak wysoki jak ja.",
            "note": "= są równego wzrostu"
        },
        {
            "en": "He is taller than me.",
            "ua": "On jest wyższy ode mnie.",
            "note": "= on jest wyższy"
        },
        {
            "en": "He is not as tall as me.",
            "ua": "On nie jest tak wysoki jak ja.",
            "note": "= jest niższy (łagodniej)"
        },
        {
            "en": "He is shorter than me.",
            "ua": "On jest niższy ode mnie.",
            "note": "= jest niższy (wprost)"
        },
        {
            "en": "This is not as expensive as I thought.",
            "ua": "To nie jest tak drogie, jak myślałem."
            ,"note": "= jest tańsze (pośrednio)"
        },
        {
            "en": "This is cheaper than I thought.",
            "ua": "To jest tańsze, niż myślałem.",
            "note": "= jest tańsze (bezpośrednio)"
        }
    ],
    "warning": "💡 Używaj <strong>as...as</strong> dla równości i łagodniejszego wyrażania nierówności, a <strong>comparative</strong> dla bezpośredniego porównania."
}

{
    "title": "7. Typowe błędy",
    "sections": [
        {
            "label": "Błąd 1: zła forma przymiotnika",
            "color": "rose",
            "description": "Użycie <strong>comparative</strong> zamiast formy podstawowej między as...as:",
            "examples": [
                {
                    "en": "❌ He is as taller as me. → ✓ He is as tall as me.",
                    "ua": "Błąd: taller zamiast tall"
                },
                {
                    "en": "❌ She is as more beautiful as her sister. → ✓ She is as beautiful as her sister.",
                    "ua": "Błąd: more beautiful"
                },
                {
                    "en": "❌ It's as better as before. → ✓ It's as good as before.",
                    "ua": "Błąd: better zamiast good"
                }
            ]
        },
        {
            "label": "Błąd 2: brak drugiego \"as\"",
            "color": "amber",
            "description": "Zapominanie o <strong>drugim as</strong> w konstrukcji:",
            "examples": [
                {
                    "en": "❌ He is as tall me. → ✓ He is as tall as me.",
                    "ua": "Błąd: brak as"
                },
                {
                    "en": "❌ She runs as fast her brother. → ✓ She runs as fast as her brother.",
                    "ua": "Błąd: brak as"
                },
                {
                    "en": "❌ It's as good before. → ✓ It's as good as before.",
                    "ua": "Błąd: brak as"
                }
            ]
        },
        {
            "label": "Błąd 3: zła pozycja not",
            "color": "sky",
            "description": "Nieprawidłowe ustawienie <strong>not</strong> w konstrukcji:",
            "examples": [
                {
                    "en": "❌ He as not tall as me. → ✓ He is not as tall as me.",
                    "ua": "Błąd: not po as"
                },
                {
                    "en": "❌ She not runs as fast as him. → ✓ She doesn't run as fast as him.",
                    "ua": "Błąd: not bez czasownika pomocniczego"
                },
                {
                    "en": "❌ It's as not good as that. → ✓ It's not as good as that.",
                    "ua": "Błąd: zła pozycja not"
                }
            ]
        },
        {
            "label": "Błąd 4: mylenie than i as",
            "color": "blue",
            "description": "Używanie <strong>than</strong> zamiast <strong>as</strong> albo odwrotnie:",
            "examples": [
                {
                    "en": "❌ He is as tall than me. → ✓ He is as tall as me / taller than me.",
                    "ua": "Błąd: as...than"
                },
                {
                    "en": "❌ She is not as fast than him. → ✓ She is not as fast as him.",
                    "ua": "Błąd: as...than"
                },
                {
                    "en": "❌ It's better as before. → ✓ It's better than before.",
                    "ua": "Błąd: comparative z as"
                }
            ]
        }
    ]
}

{
    "title": "8. Rozszerzone konstrukcje",
    "sections": [
        {
            "label": "Z twice/three times",
            "color": "emerald",
            "description": "Przed as...as można dodawać <strong>mnożniki</strong>:",
            "examples": [
                {
                    "en": "He is twice as tall as his brother.",
                    "ua": "On jest dwa razy wyższy od swojego brata."
                },
                {
                    "en": "This costs three times as much as that.",
                    "ua": "To kosztuje trzy razy tyle co tamto."
                },
                {
                    "en": "She earns half as much as him.",
                    "ua": "Ona zarabia połowę tego, co on."
                }
            ]
        },
        {
            "label": "Z nearly/almost/quite",
            "color": "blue",
            "description": "Przed pierwszym as można używać <strong>wzmacniaczy</strong>:",
            "examples": [
                {
                    "en": "He is nearly as tall as me.",
                    "ua": "On jest prawie tak wysoki jak ja."
                },
                {
                    "en": "She runs almost as fast as him.",
                    "ua": "Ona biega prawie tak szybko jak on."
                },
                {
                    "en": "It's quite as good as the original.",
                    "ua": "To jest całkiem tak dobre jak oryginał."
                }
            ]
        },
        {
            "label": "W pytaniach",
            "color": "amber",
            "description": "Konstrukcja <strong>as...as</strong> pojawia się też w zdaniach pytających:",
            "examples": [
                {
                    "en": "Is he as tall as you?",
                    "ua": "Czy on jest tak wysoki jak ty?"
                },
                {
                    "en": "Does she work as hard as her colleagues?",
                    "ua": "Czy ona pracuje tak ciężko jak jej koledzy?"
                },
                {
                    "en": "Isn't this as expensive as that one?",
                    "ua": "Czy to nie jest tak drogie jak tamto?"
                }
            ]
        }
    ]
}

{
    "title": "9. Lista kontrolna",
    "items": [
        {
            "label": "Sprawdzenie 1",
            "color": "emerald",
            "title": "Czy są oba \"as\"?",
            "wrong": "He is as tall me.",
            "right": "→ He is as tall <strong>as</strong> me."
        },
        {
            "label": "Sprawdzenie 2",
            "color": "blue",
            "title": "Czy używasz formy podstawowej?",
            "wrong": "She is as taller as him.",
            "right": "→ She is as <strong>tall</strong> as him."
        },
        {
            "label": "Sprawdzenie 3",
            "color": "rose",
            "title": "Czy not stoi we właściwym miejscu?",
            "wrong": "He as not tall as me.",
            "right": "→ He is <strong>not</strong> as tall as me."
        },
        {
            "label": "Sprawdzenie 4",
            "color": "amber",
            "title": "Czy nie mylisz as z than?",
            "wrong": "She is as tall than me.",
            "right": "→ She is as tall <strong>as</strong> me."
        }
    ]
}

{
    "title": "Kontynuuj naukę",
    "items": [
        {
            "label": "Degrees of Comparison",
            "url": "/theory/adjectives/theory-degrees-of-comparison"
        },
        {
            "label": "Comparative vs Superlative",
            "url": "/theory/adjectives/comparative-vs-superlative"
        },
        {
            "label": "Adjectives vs Adverbs",
            "url": "/theory/adjectives/adjectives-vs-adverbs"
        }
    ]
}
